 namespace WPAICG\Core\Providers\Azure\Methods; use WPAICG\Core\Providers\AzureProviderStrategy; use WPAICG\Core\Providers\Azure\AzureUrlBuilder; use WP_Error; if (!defined('ABSPATH')) { exit; } function build_api_url_logic(AzureProviderStrategy $strategyInstance, string $operation, array $params): string|WP_Error { if (!class_exists(\WPAICG\Core\Providers\Azure\AzureUrlBuilder::class)) { $url_builder_bootstrap = __DIR__ . '/bootstrap-url-builder.php'; if (file_exists($url_builder_bootstrap)) { require_once $url_builder_bootstrap; } else { return new WP_Error('azure_url_builder_missing', 'Azure URL builder component is not available.'); } } return \WPAICG\Core\Providers\Azure\AzureUrlBuilder::build($operation, $params); }